import{_ as i,C as c,o as e,c as d,a2 as n,b as o,w as a,a as l,E as r,a3 as p}from"./chunks/framework.B72_uj9U.js";const C=JSON.parse('{"title":"Tools and Projects for Code Understanding","description":"","frontmatter":{"title":"Tools and Projects for Code Understanding","status":"complete"},"headers":[],"relativePath":"research/concepts/code-understanding/tools-and-projects.md","filePath":"research/concepts/code-understanding/tools-and-projects.md"}'),y={name:"research/concepts/code-understanding/tools-and-projects.md"};function g(u,s,h,A,f,m){const t=c("Mermaid");return e(),d("div",null,[s[2]||(s[2]=n('<h1 id="tools-and-projects" tabindex="-1">Tools and Projects <a class="header-anchor" href="#tools-and-projects" aria-label="Permalink to &quot;Tools and Projects&quot;">​</a></h1><blockquote><p>A comprehensive catalog of tools, libraries, and projects that enable code understanding in coding agents — from tree-sitter parsers to Sourcegraph&#39;s code intelligence to Aider&#39;s repo map.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Code understanding in coding agents relies on a rich ecosystem of tools. Some are general-purpose (tree-sitter, ripgrep), some are purpose-built for code intelligence (Sourcegraph, SCIP), and some are specific to individual agents (Aider&#39;s repo map, Cursor&#39;s indexing). This document catalogs the major tools and how they&#39;re used.</p><h3 id="tool-landscape" tabindex="-1">Tool Landscape <a class="header-anchor" href="#tool-landscape" aria-label="Permalink to &quot;Tool Landscape&quot;">​</a></h3>',5)),(e(),o(p,null,{default:a(()=>[r(t,{id:"mermaid-17",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20subgraph%20Parsing%0A%20%20%20%20%20%20%20%20P1%5B%22tree-sitter%22%5D%0A%20%20%20%20%20%20%20%20P2%5B%22ast-grep%22%5D%0A%20%20%20%20%20%20%20%20P3%5B%22semgrep%22%5D%0A%20%20%20%20%20%20%20%20P4%5B%22ctags%22%5D%0A%20%20%20%20%20%20%20%20P5%5B%22Babel%2FSWC%22%5D%0A%20%20%20%20%20%20%20%20P6%5B%22rustc%2Fgopls%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20Search%0A%20%20%20%20%20%20%20%20S1%5B%22ripgrep%22%5D%0A%20%20%20%20%20%20%20%20S2%5B%22ast-grep%22%5D%0A%20%20%20%20%20%20%20%20S3%5B%22semgrep%22%5D%0A%20%20%20%20%20%20%20%20S4%5B%22grep%20%2F%20ag%20%2F%20ack%22%5D%0A%20%20%20%20%20%20%20%20S5%5B%22Sourcegraph%20search%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20Intelligence%0A%20%20%20%20%20%20%20%20I1%5B%22Sourcegraph%22%5D%0A%20%20%20%20%20%20%20%20I2%5B%22SCIP%2FLSIF%22%5D%0A%20%20%20%20%20%20%20%20I3%5B%22Stack%20Graphs%22%5D%0A%20%20%20%20%20%20%20%20I4%5B%22LSP%20servers%22%5D%0A%20%20%20%20%20%20%20%20I5%5B%22CodeQL%22%5D%0A%20%20%20%20%20%20%20%20I6%5B%22Kythe%22%5D%0A%20%20%20%20end%0A%20%20%20%20subgraph%20AgentSpecific%5B%22Agent-Specific%22%5D%0A%20%20%20%20%20%20%20%20A1%5B%22Aider%20repo%20map%22%5D%0A%20%20%20%20%20%20%20%20A2%5B%22Cursor%20index%22%5D%0A%20%20%20%20%20%20%20%20A3%5B%22Cody%20context%20engine%22%5D%0A%20%20%20%20%20%20%20%20A4%5B%22OpenCode%20LSP%22%5D%0A%20%20%20%20end%0A"})]),fallback:a(()=>[...s[0]||(s[0]=[l(" Loading... ",-1)])]),_:1})),s[3]||(s[3]=n(`<hr><h2 id="tree-sitter" tabindex="-1">Tree-sitter <a class="header-anchor" href="#tree-sitter" aria-label="Permalink to &quot;Tree-sitter&quot;">​</a></h2><h3 id="overview-1" tabindex="-1">Overview <a class="header-anchor" href="#overview-1" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Tree-sitter is the foundational tool for code understanding in coding agents. It&#39;s a parser generator and incremental parsing library that can build concrete syntax trees for source files and efficiently update them as files change.</p><p><strong>Repository:</strong> <a href="https://github.com/tree-sitter/tree-sitter" target="_blank" rel="noreferrer">github.com/tree-sitter/tree-sitter</a><strong>License:</strong> MIT <strong>Language:</strong> C (core), with bindings for Python, JavaScript, Rust, Go, and more</p><h3 id="key-features-for-agents" tabindex="-1">Key Features for Agents <a class="header-anchor" href="#key-features-for-agents" aria-label="Permalink to &quot;Key Features for Agents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th><th>Agent Value</th></tr></thead><tbody><tr><td><strong>Multi-language</strong></td><td>50+ language grammars available</td><td>Single tool for all languages</td></tr><tr><td><strong>Error-tolerant</strong></td><td>Produces valid ASTs for broken code</td><td>Essential for in-progress edits</td></tr><tr><td><strong>Incremental</strong></td><td>Re-parses only changed regions</td><td>Fast updates after edits</td></tr><tr><td><strong>Fast</strong></td><td>Millisecond parsing times</td><td>Real-time analysis feasible</td></tr><tr><td><strong>Query system</strong></td><td>S-expression pattern matching</td><td>Structured code extraction</td></tr></tbody></table><h3 id="agent-usage" tabindex="-1">Agent Usage <a class="header-anchor" href="#agent-usage" aria-label="Permalink to &quot;Agent Usage&quot;">​</a></h3><p><strong>Aider</strong>: Core dependency. Uses tree-sitter for tag extraction (definitions and references) that powers the repo map. Maintains language-specific <code>.scm</code> query files for tag extraction:</p><div class="language-scheme"><button title="Copy Code" class="copy"></button><span class="lang">scheme</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">;; Aider&#39;s Python tag query (simplified)</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">function_definition name: </span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">identifier</span><span style="color:#9399B2;">)</span><span style="color:#CDD6F4;"> @name</span><span style="color:#9399B2;">)</span><span style="color:#CDD6F4;"> @definition.function</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">class_definition name: </span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">identifier</span><span style="color:#9399B2;">)</span><span style="color:#CDD6F4;"> @name</span><span style="color:#9399B2;">)</span><span style="color:#CDD6F4;"> @definition.class</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">call function: </span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">identifier</span><span style="color:#9399B2;">)</span><span style="color:#CDD6F4;"> @name</span><span style="color:#9399B2;">)</span><span style="color:#CDD6F4;"> @reference.call</span></span>
<span class="line"><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">call function: </span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">attribute attribute: </span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">identifier</span><span style="color:#9399B2;">)</span><span style="color:#CDD6F4;"> @name</span><span style="color:#9399B2;">))</span><span style="color:#CDD6F4;"> @reference.call</span></span></code></pre></div><p><strong>Claude Code</strong>: Uses tree-sitter for file summarization in its View tool — extracting function signatures and class definitions to provide structural overviews without reading full file contents.</p><p><strong>Droid</strong>: Uses tree-sitter for incremental indexing — parsing files as they change and updating the symbol index.</p><p><strong>Ante</strong>: Uses tree-sitter for symbol extraction before embedding generation.</p><h3 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h3><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Python binding</span></span>
<span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> tree_sitter_python </span><span style="color:#CBA6F7;">as</span><span style="color:#CDD6F4;"> tspython</span></span>
<span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#CDD6F4;"> tree_sitter </span><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> Language</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> Parser</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">PY_LANGUAGE </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> Language</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tspython</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">language</span><span style="color:#9399B2;">())</span></span>
<span class="line"><span style="color:#CDD6F4;">parser </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;"> Parser</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">PY_LANGUAGE</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">source </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;font-style:italic;"> b</span><span style="color:#A6E3A1;">&quot;&quot;&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">def hello(name):</span></span>
<span class="line"><span style="color:#A6E3A1;">    print(f&quot;Hello, {name}!&quot;)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#A6E3A1;">class Greeter:</span></span>
<span class="line"><span style="color:#A6E3A1;">    def greet(self, name):</span></span>
<span class="line"><span style="color:#A6E3A1;">        return f&quot;Hi, {name}&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">&quot;&quot;&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">tree </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> parser</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">parse</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">source</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CDD6F4;">root </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> tree</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">root_node</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Walk the tree</span></span>
<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> walk</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">node</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> depth</span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;">0</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    print</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;  &quot;</span><span style="color:#94E2D5;"> *</span><span style="color:#CDD6F4;"> depth </span><span style="color:#94E2D5;">+</span><span style="color:#A6E3A1;font-style:italic;"> f</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#F5C2E7;">{</span><span style="color:#CDD6F4;">node</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">type</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">: </span><span style="color:#F5C2E7;">{</span><span style="color:#CDD6F4;">node</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">text</span><span style="color:#9399B2;">[:</span><span style="color:#FAB387;font-style:italic;">50</span><span style="color:#9399B2;">]</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">    for</span><span style="color:#CDD6F4;"> child </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> node</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">children</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#89B4FA;">        walk</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">child</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> depth </span><span style="color:#94E2D5;">+</span><span style="color:#FAB387;"> 1</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;">walk</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">root</span><span style="color:#9399B2;">)</span></span></code></pre></div><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Node.js binding</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">npm</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> tree-sitter</span><span style="color:#A6E3A1;"> tree-sitter-python</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Rust binding</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># In Cargo.toml:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># [dependencies]</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># tree-sitter = &quot;0.22&quot;</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># tree-sitter-python = &quot;0.21&quot;</span></span></code></pre></div><h3 id="language-grammars" tabindex="-1">Language Grammars <a class="header-anchor" href="#language-grammars" aria-label="Permalink to &quot;Language Grammars&quot;">​</a></h3><p>Popular grammars maintained by the tree-sitter organization:</p><table tabindex="0"><thead><tr><th>Language</th><th>Grammar Package</th><th>Maturity</th></tr></thead><tbody><tr><td>Python</td><td>tree-sitter-python</td><td>Stable</td></tr><tr><td>JavaScript</td><td>tree-sitter-javascript</td><td>Stable</td></tr><tr><td>TypeScript</td><td>tree-sitter-typescript</td><td>Stable</td></tr><tr><td>Rust</td><td>tree-sitter-rust</td><td>Stable</td></tr><tr><td>Go</td><td>tree-sitter-go</td><td>Stable</td></tr><tr><td>Java</td><td>tree-sitter-java</td><td>Stable</td></tr><tr><td>C</td><td>tree-sitter-c</td><td>Stable</td></tr><tr><td>C++</td><td>tree-sitter-cpp</td><td>Stable</td></tr><tr><td>Ruby</td><td>tree-sitter-ruby</td><td>Stable</td></tr><tr><td>PHP</td><td>tree-sitter-php</td><td>Stable</td></tr><tr><td>C#</td><td>tree-sitter-c-sharp</td><td>Stable</td></tr><tr><td>Bash</td><td>tree-sitter-bash</td><td>Stable</td></tr><tr><td>HTML</td><td>tree-sitter-html</td><td>Stable</td></tr><tr><td>CSS</td><td>tree-sitter-css</td><td>Stable</td></tr><tr><td>JSON</td><td>tree-sitter-json</td><td>Stable</td></tr></tbody></table><hr><h2 id="ast-grep" tabindex="-1">ast-grep <a class="header-anchor" href="#ast-grep" aria-label="Permalink to &quot;ast-grep&quot;">​</a></h2><h3 id="overview-2" tabindex="-1">Overview <a class="header-anchor" href="#overview-2" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>ast-grep is a fast, polyglot tool for searching, linting, and rewriting code using AST patterns. It uses tree-sitter under the hood but provides a much more ergonomic interface for structural code search.</p><p><strong>Repository:</strong> <a href="https://github.com/ast-grep/ast-grep" target="_blank" rel="noreferrer">github.com/ast-grep/ast-grep</a><strong>License:</strong> MIT <strong>Language:</strong> Rust</p><h3 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h3><ul><li><strong>Pattern matching</strong>: Write patterns that look like code — <code>console.log($$$ARGS)</code> matches all console.log calls</li><li><strong>Multi-language</strong>: Supports all tree-sitter languages</li><li><strong>YAML rules</strong>: Write linting rules in simple YAML</li><li><strong>Language server</strong>: Built-in LSP for IDE integration</li><li><strong>Performance</strong>: Rust-based, handles thousands of files in seconds</li></ul><h3 id="usage-examples" tabindex="-1">Usage Examples <a class="header-anchor" href="#usage-examples" aria-label="Permalink to &quot;Usage Examples&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Find all useState calls in React</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ast-grep</span><span style="color:#A6E3A1;"> --pattern</span><span style="color:#A6E3A1;"> &#39;const [$STATE, $SETTER] = useState($INIT)&#39;</span><span style="color:#A6E3A1;"> --lang</span><span style="color:#A6E3A1;"> tsx</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Find all async functions</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ast-grep</span><span style="color:#A6E3A1;"> --pattern</span><span style="color:#A6E3A1;"> &#39;async function $NAME($$$PARAMS) { $$$BODY }&#39;</span><span style="color:#A6E3A1;"> --lang</span><span style="color:#A6E3A1;"> ts</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Find all try-catch blocks</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ast-grep</span><span style="color:#A6E3A1;"> --pattern</span><span style="color:#A6E3A1;"> &#39;try { $$$BODY } catch ($ERR) { $$$HANDLER }&#39;</span><span style="color:#A6E3A1;"> --lang</span><span style="color:#A6E3A1;"> ts</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Rewrite: replace var with let</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ast-grep</span><span style="color:#A6E3A1;"> --pattern</span><span style="color:#A6E3A1;"> &#39;var $NAME = $VALUE&#39;</span><span style="color:#A6E3A1;"> --rewrite</span><span style="color:#A6E3A1;"> &#39;let $NAME = $VALUE&#39;</span><span style="color:#A6E3A1;"> --lang</span><span style="color:#A6E3A1;"> js</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Rewrite: convert require to import</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ast-grep</span><span style="color:#A6E3A1;"> --pattern</span><span style="color:#A6E3A1;"> &#39;const $NAME = require($PATH)&#39;</span><span style="color:#F5C2E7;"> \\</span></span>
<span class="line"><span style="color:#A6E3A1;">  --rewrite</span><span style="color:#A6E3A1;"> &#39;import $NAME from $PATH&#39;</span><span style="color:#A6E3A1;"> --lang</span><span style="color:#A6E3A1;"> js</span></span></code></pre></div><h3 id="yaml-rule-example" tabindex="-1">YAML Rule Example <a class="header-anchor" href="#yaml-rule-example" aria-label="Permalink to &quot;YAML Rule Example&quot;">​</a></h3><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Rule to find potential security issues</span></span>
<span class="line"><span style="color:#89B4FA;">id</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> no-eval</span></span>
<span class="line"><span style="color:#89B4FA;">language</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> javascript</span></span>
<span class="line"><span style="color:#89B4FA;">rule</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  pattern</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> eval($CODE)</span></span>
<span class="line"><span style="color:#89B4FA;">message</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;Avoid using eval() — it&#39;s a security risk&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">severity</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> error</span></span>
<span class="line"><span style="color:#89B4FA;">note</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;Consider using JSON.parse() for data or Function() for dynamic code&quot;</span></span></code></pre></div><h3 id="agent-integration-opportunity" tabindex="-1">Agent Integration Opportunity <a class="header-anchor" href="#agent-integration-opportunity" aria-label="Permalink to &quot;Agent Integration Opportunity&quot;">​</a></h3><p>ast-grep is significantly underutilized by coding agents. Its pattern-based search would allow agents to:</p><ol><li><strong>Find structural patterns</strong>: &quot;All Express route handlers&quot; → <code>app.$METHOD($PATH, $$$MIDDLEWARE, $HANDLER)</code></li><li><strong>Verify conventions</strong>: &quot;Ensure all async functions have try-catch&quot; → YAML rule</li><li><strong>Safe refactoring</strong>: &quot;Rename this pattern across all files&quot; → pattern + rewrite</li></ol><hr><h2 id="semgrep" tabindex="-1">Semgrep <a class="header-anchor" href="#semgrep" aria-label="Permalink to &quot;Semgrep&quot;">​</a></h2><h3 id="overview-3" tabindex="-1">Overview <a class="header-anchor" href="#overview-3" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Semgrep is a fast, open-source static analysis tool that finds bugs, vulnerabilities, and anti-patterns using lightweight rules. It&#39;s more mature than ast-grep and has a large community rule library.</p><p><strong>Repository:</strong> <a href="https://github.com/semgrep/semgrep" target="_blank" rel="noreferrer">github.com/semgrep/semgrep</a><strong>License:</strong> LGPL 2.1 (OSS engine), proprietary (cloud platform) <strong>Language:</strong> OCaml (core), Python (CLI)</p><h3 id="key-features-1" tabindex="-1">Key Features <a class="header-anchor" href="#key-features-1" aria-label="Permalink to &quot;Key Features&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Pattern matching</strong></td><td>Code patterns with metavariables</td></tr><tr><td><strong>Cross-file analysis</strong></td><td>Track data flow across files (Pro)</td></tr><tr><td><strong>Rule registry</strong></td><td>3000+ community rules</td></tr><tr><td><strong>CI integration</strong></td><td>GitHub Actions, GitLab CI</td></tr><tr><td><strong>Multi-language</strong></td><td>30+ languages supported</td></tr></tbody></table><h3 id="usage-for-code-understanding" tabindex="-1">Usage for Code Understanding <a class="header-anchor" href="#usage-for-code-understanding" aria-label="Permalink to &quot;Usage for Code Understanding&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Find SQL injection vulnerabilities</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">semgrep</span><span style="color:#A6E3A1;"> --config</span><span style="color:#A6E3A1;"> &quot;p/owasp-top-ten&quot;</span><span style="color:#A6E3A1;"> .</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Find hardcoded secrets</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">semgrep</span><span style="color:#A6E3A1;"> --config</span><span style="color:#A6E3A1;"> &quot;p/secrets&quot;</span><span style="color:#A6E3A1;"> .</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Custom pattern: find all database queries</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">semgrep</span><span style="color:#A6E3A1;"> --pattern</span><span style="color:#A6E3A1;"> &#39;db.query($SQL)&#39;</span><span style="color:#A6E3A1;"> --lang</span><span style="color:#A6E3A1;"> python</span><span style="color:#A6E3A1;"> .</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Custom pattern: find unhandled promises</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">semgrep</span><span style="color:#A6E3A1;"> --pattern</span><span style="color:#A6E3A1;"> &#39;await $PROMISE&#39;</span><span style="color:#A6E3A1;"> --lang</span><span style="color:#A6E3A1;"> typescript</span><span style="color:#A6E3A1;"> .</span></span></code></pre></div><h3 id="semgrep-rule-example" tabindex="-1">Semgrep Rule Example <a class="header-anchor" href="#semgrep-rule-example" aria-label="Permalink to &quot;Semgrep Rule Example&quot;">​</a></h3><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">rules</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">  -</span><span style="color:#89B4FA;"> id</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> unsafe-deserialization</span></span>
<span class="line"><span style="color:#89B4FA;">    pattern</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> |</span></span>
<span class="line"><span style="color:#A6E3A1;">      pickle.loads($DATA)</span></span>
<span class="line"><span style="color:#89B4FA;">    message</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;Unsafe deserialization with pickle — use json.loads() for untrusted data&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">    languages</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">python</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#89B4FA;">    severity</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> ERROR</span></span>
<span class="line"><span style="color:#89B4FA;">    metadata</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">      cwe</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;CWE-502&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">      owasp</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;A8: Insecure Deserialization&quot;</span></span></code></pre></div><hr><h2 id="universal-ctags" tabindex="-1">Universal Ctags <a class="header-anchor" href="#universal-ctags" aria-label="Permalink to &quot;Universal Ctags&quot;">​</a></h2><h3 id="overview-4" tabindex="-1">Overview <a class="header-anchor" href="#overview-4" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Universal Ctags is the modern successor to Exuberant Ctags, a tool that generates tag files mapping symbol names to their locations in source files. While older than tree-sitter, ctags is still widely used and supports over 100 languages.</p><p><strong>Repository:</strong> <a href="https://github.com/universal-ctags/ctags" target="_blank" rel="noreferrer">github.com/universal-ctags/ctags</a><strong>License:</strong> GPL v2 <strong>Language:</strong> C</p><h3 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Generate tags for a project</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ctags</span><span style="color:#A6E3A1;"> -R</span><span style="color:#A6E3A1;"> --fields=+lnS</span><span style="color:#A6E3A1;"> --extras=+q</span><span style="color:#A6E3A1;"> .</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Output format</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># TagName&lt;TAB&gt;FileName&lt;TAB&gt;ExCommand;&quot;&lt;TAB&gt;Kind&lt;TAB&gt;Extras</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># UserService  src/services/user.ts  /^export class UserService/;&quot;  c</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Generate tags with specific languages</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ctags</span><span style="color:#A6E3A1;"> --languages=TypeScript,JavaScript</span><span style="color:#A6E3A1;"> -R</span><span style="color:#A6E3A1;"> .</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># JSON output</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">ctags</span><span style="color:#A6E3A1;"> --output-format=json</span><span style="color:#A6E3A1;"> -R</span><span style="color:#A6E3A1;"> .</span></span></code></pre></div><h3 id="comparison-with-tree-sitter-tags" tabindex="-1">Comparison with Tree-sitter Tags <a class="header-anchor" href="#comparison-with-tree-sitter-tags" aria-label="Permalink to &quot;Comparison with Tree-sitter Tags&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Universal Ctags</th><th>Tree-sitter Tags</th></tr></thead><tbody><tr><td><strong>Languages</strong></td><td>100+</td><td>50+</td></tr><tr><td><strong>References</strong></td><td>Definitions only</td><td>Definitions AND references</td></tr><tr><td><strong>Precision</strong></td><td>Line-level</td><td>Character-level</td></tr><tr><td><strong>Incremental</strong></td><td>No (regenerate all)</td><td>Yes (incremental parsing)</td></tr><tr><td><strong>Error tolerance</strong></td><td>Limited</td><td>Full (produces ASTs for broken code)</td></tr><tr><td><strong>Speed</strong></td><td>Fast</td><td>Faster</td></tr><tr><td><strong>Graph building</strong></td><td>Not possible (no references)</td><td>Possible (definition-reference links)</td></tr></tbody></table><hr><h2 id="sourcegraph-and-code-intelligence" tabindex="-1">Sourcegraph and Code Intelligence <a class="header-anchor" href="#sourcegraph-and-code-intelligence" aria-label="Permalink to &quot;Sourcegraph and Code Intelligence&quot;">​</a></h2><h3 id="sourcegraph-overview" tabindex="-1">Sourcegraph Overview <a class="header-anchor" href="#sourcegraph-overview" aria-label="Permalink to &quot;Sourcegraph Overview&quot;">​</a></h3><p>Sourcegraph is a code intelligence platform that provides search, navigation, and insights across all codebases. While primarily a hosted service, its code intelligence capabilities are highly relevant to coding agents.</p><p><strong>Website:</strong> <a href="https://sourcegraph.com" target="_blank" rel="noreferrer">sourcegraph.com</a><strong>Key projects:</strong> Cody (AI assistant), SCIP, Zoekt</p><h3 id="scip-sourcegraph-code-intelligence-protocol" tabindex="-1">SCIP (Sourcegraph Code Intelligence Protocol) <a class="header-anchor" href="#scip-sourcegraph-code-intelligence-protocol" aria-label="Permalink to &quot;SCIP (Sourcegraph Code Intelligence Protocol)&quot;">​</a></h3><p>SCIP is a language-agnostic protocol for indexing source code. Unlike LSP (which requires a running server), SCIP produces a static index that can be queried offline.</p><div class="language-protobuf"><button title="Copy Code" class="copy"></button><span class="lang">protobuf</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// SCIP index structure (simplified)</span></span>
<span class="line"><span style="color:#CBA6F7;">message</span><span style="color:#F9E2AF;font-style:italic;"> Index</span><span style="color:#CDD6F4;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">  repeated</span><span style="color:#CBA6F7;"> Document</span><span style="color:#CDD6F4;"> documents </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 1</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CDD6F4;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">message</span><span style="color:#F9E2AF;font-style:italic;"> Document</span><span style="color:#CDD6F4;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">  string</span><span style="color:#CDD6F4;"> relative_path </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 1</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">  repeated</span><span style="color:#CBA6F7;"> Occurrence</span><span style="color:#CDD6F4;"> occurrences </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 2</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">  repeated</span><span style="color:#CBA6F7;"> SymbolInformation</span><span style="color:#CDD6F4;"> symbols </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 3</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CDD6F4;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">message</span><span style="color:#F9E2AF;font-style:italic;"> Occurrence</span><span style="color:#CDD6F4;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">  Range</span><span style="color:#CDD6F4;"> range </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 1</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">  string</span><span style="color:#CDD6F4;"> symbol </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 2</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">  SymbolRole</span><span style="color:#CDD6F4;"> symbol_roles </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;"> 3</span><span style="color:#9399B2;">;</span><span style="color:#6C7086;font-style:italic;">  // Definition, Reference, Import, etc.</span></span>
<span class="line"><span style="color:#CDD6F4;">}</span></span></code></pre></div><p><strong>SCIP indexers available:</strong></p><ul><li>scip-typescript (TypeScript/JavaScript)</li><li>scip-python (Python)</li><li>scip-java (Java/Kotlin)</li><li>scip-go (Go)</li><li>scip-rust (Rust via rust-analyzer)</li><li>scip-ruby (Ruby)</li><li>scip-dotnet (C#/F#)</li></ul><h3 id="lsif-language-server-index-format" tabindex="-1">LSIF (Language Server Index Format) <a class="header-anchor" href="#lsif-language-server-index-format" aria-label="Permalink to &quot;LSIF (Language Server Index Format)&quot;">​</a></h3><p>LSIF is the predecessor to SCIP — a format for dumping LSP data to a file:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Generate LSIF index for TypeScript</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">npx</span><span style="color:#A6E3A1;"> lsif-tsc</span><span style="color:#A6E3A1;"> -p</span><span style="color:#A6E3A1;"> tsconfig.json</span><span style="color:#A6E3A1;"> --out</span><span style="color:#A6E3A1;"> index.lsif</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Generate LSIF index for Go</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">lsif-go</span><span style="color:#A6E3A1;"> --out</span><span style="color:#A6E3A1;"> index.lsif</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Upload to Sourcegraph</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">src</span><span style="color:#A6E3A1;"> lsif</span><span style="color:#A6E3A1;"> upload</span><span style="color:#A6E3A1;"> -file=index.lsif</span></span></code></pre></div><p><strong>Agent opportunity:</strong> SCIP/LSIF indexes could provide offline code intelligence to agents without the startup cost of running a language server.</p><h3 id="zoekt-search-engine" tabindex="-1">Zoekt (Search Engine) <a class="header-anchor" href="#zoekt-search-engine" aria-label="Permalink to &quot;Zoekt (Search Engine)&quot;">​</a></h3><p>Zoekt is Sourcegraph&#39;s code search engine, optimized for searching across millions of repositories:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Install zoekt</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">go</span><span style="color:#A6E3A1;"> install</span><span style="color:#A6E3A1;"> github.com/sourcegraph/zoekt/cmd/...@latest</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Index a repository</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">zoekt-index</span><span style="color:#A6E3A1;"> /path/to/repo</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Search</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">zoekt</span><span style="color:#A6E3A1;"> &quot;class.*Service.*implements&quot;</span><span style="color:#A6E3A1;"> -r</span></span></code></pre></div><hr><h2 id="cody-s-context-engine" tabindex="-1">Cody&#39;s Context Engine <a class="header-anchor" href="#cody-s-context-engine" aria-label="Permalink to &quot;Cody&#39;s Context Engine&quot;">​</a></h2><h3 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h3><p>Sourcegraph Cody uses a multi-layered context retrieval system:</p>`,74)),(e(),o(p,null,{default:a(()=>[r(t,{id:"mermaid-668",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20Q%5B%22User%20Query%22%5D%0A%20%20%20%20QR%5B%22Query%20Rewriting%3Cbr%2F%3EExpand%20with%20synonyms%2C%20related%20terms%22%5D%0A%20%20%20%20KS%5B%22Keyword%20Search%22%5D%0A%20%20%20%20CG%5B%22Code%20Graph%20Analysis%22%5D%0A%20%20%20%20SS%5B%22Sourcegraph%20Search%22%5D%0A%20%20%20%20CA%5B%22Context%20Assembly%3Cbr%2F%3ERank%2C%20deduplicate%2C%20select%20top-k%22%5D%0A%20%20%20%20LP%5B%22LLM%20Prompt%3Cbr%2F%3EInclude%20selected%20context%20in%20prompt%22%5D%0A%20%20%20%20Q%20--%3E%20QR%0A%20%20%20%20QR%20--%3E%20KS%0A%20%20%20%20QR%20--%3E%20CG%0A%20%20%20%20QR%20--%3E%20SS%0A%20%20%20%20KS%20--%3E%20CA%0A%20%20%20%20CG%20--%3E%20CA%0A%20%20%20%20SS%20--%3E%20CA%0A%20%20%20%20CA%20--%3E%20LP%0A"})]),fallback:a(()=>[...s[1]||(s[1]=[l(" Loading... ",-1)])]),_:1})),s[4]||(s[4]=n(`<h3 id="context-sources" tabindex="-1">Context Sources <a class="header-anchor" href="#context-sources" aria-label="Permalink to &quot;Context Sources&quot;">​</a></h3><ol><li><strong>Keyword Search</strong>: Traditional text matching with query rewriting</li><li><strong>Code Graph</strong>: Structural analysis of imports, definitions, references</li><li><strong>Sourcegraph Search</strong>: Powerful cross-repository search via the Sourcegraph API</li><li><strong>@-mentions</strong>: User-specified files, symbols, or repositories</li></ol><hr><h2 id="aider-s-repo-map" tabindex="-1">Aider&#39;s Repo Map <a class="header-anchor" href="#aider-s-repo-map" aria-label="Permalink to &quot;Aider&#39;s Repo Map&quot;">​</a></h2><h3 id="deep-dive" tabindex="-1">Deep Dive <a class="header-anchor" href="#deep-dive" aria-label="Permalink to &quot;Deep Dive&quot;">​</a></h3><p>Aider&#39;s repo map is the most influential code understanding tool specific to CLI coding agents. It deserves detailed analysis because it demonstrates what&#39;s possible with relatively simple techniques.</p><p><strong>Repository:</strong> <a href="https://github.com/Aider-AI/aider" target="_blank" rel="noreferrer">github.com/Aider-AI/aider</a><strong>Key file:</strong> <code>aider/repomap.py</code></p><h3 id="architecture-1" tabindex="-1">Architecture <a class="header-anchor" href="#architecture-1" aria-label="Permalink to &quot;Architecture&quot;">​</a></h3><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Simplified RepoMap pipeline</span></span>
<span class="line"><span style="color:#CBA6F7;">class</span><span style="color:#F9E2AF;font-style:italic;"> RepoMap</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#CBA6F7;">    def</span><span style="color:#89B4FA;font-style:italic;"> get_repo_map</span><span style="color:#9399B2;">(</span><span style="color:#F38BA8;font-style:italic;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> chat_fnames</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> other_fnames</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # 1. Get tags for all files</span></span>
<span class="line"><span style="color:#CDD6F4;">        all_tags </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {}</span></span>
<span class="line"><span style="color:#CBA6F7;">        for</span><span style="color:#CDD6F4;"> fname </span><span style="color:#CBA6F7;">in</span><span style="color:#89B4FA;"> chain</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">chat_fnames</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> other_fnames</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#EBA0AC;font-style:italic;">            all_tags</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">fname</span><span style="color:#9399B2;">]</span><span style="color:#94E2D5;"> =</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">get_tags</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">fname</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">  # tree-sitter</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # 2. Build reference graph</span></span>
<span class="line"><span style="color:#CDD6F4;">        G </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">build_reference_graph</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">all_tags</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # 3. Rank with PageRank (personalized to chat files)</span></span>
<span class="line"><span style="color:#CDD6F4;">        ranked </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">rank_with_pagerank</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">G</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> chat_fnames</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # 4. Select top-ranked tags within token budget</span></span>
<span class="line"><span style="color:#CDD6F4;">        selected </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">select_within_budget</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">ranked</span><span style="color:#9399B2;">,</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">max_map_tokens</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        # 5. Render as text</span></span>
<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#F38BA8;font-style:italic;"> self</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">render_map</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">selected</span><span style="color:#9399B2;">)</span></span></code></pre></div><h3 id="key-design-decisions" tabindex="-1">Key Design Decisions <a class="header-anchor" href="#key-design-decisions" aria-label="Permalink to &quot;Key Design Decisions&quot;">​</a></h3><ol><li><p><strong>PageRank, not frequency</strong>: Aider doesn&#39;t just count references — it uses PageRank to find symbols that are <em>important</em> (referenced by many important files), not just <em>frequent</em>.</p></li><li><p><strong>Personalization</strong>: The PageRank is personalized toward files the user has added to the chat, boosting symbols relevant to the current task.</p></li><li><p><strong>Token budgeting</strong>: The map is constrained to a token budget (default 1024 tokens), dynamically expanded when no files are in the chat.</p></li><li><p><strong>Definition-focused output</strong>: The map shows function signatures and class definitions, not full implementations — maximizing information density.</p></li></ol><h3 id="example-output" tabindex="-1">Example Output <a class="header-anchor" href="#example-output" aria-label="Permalink to &quot;Example Output&quot;">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>src/services/auth.ts:</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│export class AuthService:</span></span>
<span class="line"><span>│    constructor(private db: Database, private jwt: JwtService)</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│    async authenticate(email: string, password: string): Promise&lt;User&gt;</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│    async refreshToken(token: string): Promise&lt;TokenPair&gt;</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>src/models/user.ts:</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│export interface User:</span></span>
<span class="line"><span>│    id: string</span></span>
<span class="line"><span>│    email: string</span></span>
<span class="line"><span>│    role: UserRole</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>src/middleware/auth.ts:</span></span>
<span class="line"><span>⋮...</span></span>
<span class="line"><span>│export function requireAuth(roles?: UserRole[]):</span></span>
<span class="line"><span>⋮...</span></span></code></pre></div><hr><h2 id="cursor-s-codebase-indexing" tabindex="-1">Cursor&#39;s Codebase Indexing <a class="header-anchor" href="#cursor-s-codebase-indexing" aria-label="Permalink to &quot;Cursor&#39;s Codebase Indexing&quot;">​</a></h2><h3 id="overview-5" tabindex="-1">Overview <a class="header-anchor" href="#overview-5" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Cursor (the AI-native code editor) uses embedding-based indexing as a core feature:</p><ol><li><strong>On project open</strong>: Cursor indexes the entire codebase, generating embeddings for code chunks</li><li><strong>Semantic search</strong>: When the user asks a question, Cursor searches the embedding index for relevant code</li><li><strong>Context injection</strong>: Relevant code chunks are automatically included in LLM prompts</li><li><strong>Incremental updates</strong>: As files change, embeddings are updated incrementally</li></ol><h3 id="technical-details" tabindex="-1">Technical Details <a class="header-anchor" href="#technical-details" aria-label="Permalink to &quot;Technical Details&quot;">​</a></h3><ul><li><strong>Embedding model</strong>: Custom model optimized for code (details not public)</li><li><strong>Chunking strategy</strong>: Function-level chunks with AST awareness</li><li><strong>Storage</strong>: Local embedding database (not sent to cloud)</li><li><strong>Hybrid search</strong>: Combines embedding similarity with keyword matching</li></ul><h3 id="relevance-to-cli-agents" tabindex="-1">Relevance to CLI Agents <a class="header-anchor" href="#relevance-to-cli-agents" aria-label="Permalink to &quot;Relevance to CLI Agents&quot;">​</a></h3><p>Cursor&#39;s approach works well for an IDE (always running, persistent state) but faces challenges for CLI agents:</p><ul><li><strong>Startup cost</strong>: Embedding generation takes minutes</li><li><strong>Storage</strong>: Embeddings require persistent local storage</li><li><strong>Dependencies</strong>: Requires an embedding model (API or local)</li></ul><hr><h2 id="github-s-stack-graphs" tabindex="-1">GitHub&#39;s Stack Graphs <a class="header-anchor" href="#github-s-stack-graphs" aria-label="Permalink to &quot;GitHub&#39;s Stack Graphs&quot;">​</a></h2><h3 id="overview-6" tabindex="-1">Overview <a class="header-anchor" href="#overview-6" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>Stack Graphs is a library from GitHub for implementing name resolution without a running language server. It defines a graph structure where names are resolved by finding paths through the graph.</p><p><strong>Repository:</strong> <a href="https://github.com/github/stack-graphs" target="_blank" rel="noreferrer">github.com/github/stack-graphs</a><strong>License:</strong> MIT/Apache 2.0 <strong>Language:</strong> Rust</p><h3 id="key-innovation" tabindex="-1">Key Innovation <a class="header-anchor" href="#key-innovation" aria-label="Permalink to &quot;Key Innovation&quot;">​</a></h3><p>Stack Graphs separate name resolution into per-file partial graphs that can be computed independently and composed later. This enables:</p><ul><li><strong>Incremental computation</strong>: Only re-process changed files</li><li><strong>Parallel processing</strong>: Files can be analyzed independently</li><li><strong>Offline usage</strong>: No running server needed</li></ul><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Stack Graphs concept (simplified)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Each file contributes partial name resolution information:</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// File: src/models.py</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Exports: User, Post</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// No imports</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// File: src/api.py</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Imports: User from models</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Exports: create_user, get_user</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// Stack Graphs connects these:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// api.py::User → models.py::User (resolved)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// api.py::create_user → returns models.py::User (type flow)</span></span></code></pre></div><h3 id="agent-opportunity" tabindex="-1">Agent Opportunity <a class="header-anchor" href="#agent-opportunity" aria-label="Permalink to &quot;Agent Opportunity&quot;">​</a></h3><p>Stack Graphs could provide precise name resolution for agents without the overhead of running language servers — filling the gap between tree-sitter&#39;s structural analysis and LSP&#39;s semantic understanding.</p><hr><h2 id="codeql" tabindex="-1">CodeQL <a class="header-anchor" href="#codeql" aria-label="Permalink to &quot;CodeQL&quot;">​</a></h2><h3 id="overview-7" tabindex="-1">Overview <a class="header-anchor" href="#overview-7" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>CodeQL is GitHub&#39;s semantic code analysis engine. It treats code as data, allowing SQL-like queries over code structures.</p><p><strong>Repository:</strong> <a href="https://github.com/github/codeql" target="_blank" rel="noreferrer">github.com/github/codeql</a><strong>License:</strong> MIT (queries), proprietary (engine)</p><div class="language-ql"><button title="Copy Code" class="copy"></button><span class="lang">ql</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Find all SQL injection vulnerabilities in Python</span></span>
<span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#F9E2AF;font-style:italic;"> python</span></span>
<span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#F9E2AF;font-style:italic;"> semmle</span><span style="color:#94E2D5;">.</span><span style="color:#F9E2AF;font-style:italic;">python</span><span style="color:#94E2D5;">.</span><span style="color:#F9E2AF;font-style:italic;">security</span><span style="color:#94E2D5;">.</span><span style="color:#F9E2AF;font-style:italic;">dataflow</span><span style="color:#94E2D5;">.</span><span style="color:#F9E2AF;font-style:italic;">SqlInjectionQuery</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">from</span><span style="color:#F9E2AF;font-style:italic;"> SqlInjectionConfiguration</span><span style="color:#EBA0AC;font-style:italic;"> config</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> DataFlow</span><span style="color:#CDD6F4;">::</span><span style="color:#F9E2AF;font-style:italic;">PathNode</span><span style="color:#EBA0AC;font-style:italic;"> source</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> DataFlow</span><span style="color:#CDD6F4;">::</span><span style="color:#F9E2AF;font-style:italic;">PathNode</span><span style="color:#EBA0AC;font-style:italic;"> sink</span></span>
<span class="line"><span style="color:#CBA6F7;">where</span><span style="color:#CDD6F4;"> config</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">hasFlowPath</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">source</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> sink</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#CBA6F7;">select</span><span style="color:#CDD6F4;"> sink</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">getNode</span><span style="color:#9399B2;">(),</span><span style="color:#CDD6F4;"> source</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> sink</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;SQL injection from $@.&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> source</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">getNode</span><span style="color:#9399B2;">(),</span><span style="color:#A6E3A1;"> &quot;user input&quot;</span></span></code></pre></div><h3 id="relevance-to-agents" tabindex="-1">Relevance to Agents <a class="header-anchor" href="#relevance-to-agents" aria-label="Permalink to &quot;Relevance to Agents&quot;">​</a></h3><p>CodeQL is too heavy for real-time agent use (database creation takes minutes to hours for large codebases). However, its approach — querying code as data — inspires lighter-weight alternatives that agents could use.</p><hr><h2 id="comparison-matrix" tabindex="-1">Comparison Matrix <a class="header-anchor" href="#comparison-matrix" aria-label="Permalink to &quot;Comparison Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Type</th><th>Languages</th><th>Speed</th><th>Agent Usage</th><th>Best For</th></tr></thead><tbody><tr><td><strong>tree-sitter</strong></td><td>Parser</td><td>50+</td><td>Very Fast</td><td>High (Aider, Claude Code, Droid)</td><td>AST construction, tag extraction</td></tr><tr><td><strong>ast-grep</strong></td><td>Search/Lint</td><td>20+</td><td>Fast</td><td>Very Low</td><td>Structural code search</td></tr><tr><td><strong>semgrep</strong></td><td>Search/SAST</td><td>30+</td><td>Moderate</td><td>Very Low</td><td>Security analysis, pattern matching</td></tr><tr><td><strong>Universal Ctags</strong></td><td>Tag generator</td><td>100+</td><td>Fast</td><td>Low</td><td>Symbol indexing</td></tr><tr><td><strong>ripgrep</strong></td><td>Text search</td><td>All</td><td>Very Fast</td><td>Universal</td><td>Text search across files</td></tr><tr><td><strong>Sourcegraph</strong></td><td>Platform</td><td>All</td><td>Fast</td><td>Indirect (Cody)</td><td>Cross-repo code intelligence</td></tr><tr><td><strong>SCIP/LSIF</strong></td><td>Index format</td><td>10+</td><td>N/A (pre-built)</td><td>None yet</td><td>Offline code intelligence</td></tr><tr><td><strong>Stack Graphs</strong></td><td>Name resolver</td><td>3</td><td>Fast</td><td>None yet</td><td>Cross-file name resolution</td></tr><tr><td><strong>CodeQL</strong></td><td>Analysis engine</td><td>10+</td><td>Slow</td><td>None</td><td>Deep security analysis</td></tr><tr><td><strong>Aider repo map</strong></td><td>Agent feature</td><td>50+</td><td>Fast</td><td>Aider only</td><td>Codebase overview for LLMs</td></tr><tr><td><strong>Cursor indexing</strong></td><td>IDE feature</td><td>All</td><td>Moderate</td><td>Cursor only</td><td>Embedding-based code search</td></tr><tr><td><strong>Cody context</strong></td><td>Platform feature</td><td>All</td><td>Fast</td><td>Cody only</td><td>Multi-source context retrieval</td></tr></tbody></table><hr><h2 id="emerging-tools-and-trends" tabindex="-1">Emerging Tools and Trends <a class="header-anchor" href="#emerging-tools-and-trends" aria-label="Permalink to &quot;Emerging Tools and Trends&quot;">​</a></h2><h3 id="moatless-tools" tabindex="-1">Moatless Tools <a class="header-anchor" href="#moatless-tools" aria-label="Permalink to &quot;Moatless Tools&quot;">​</a></h3><p>Repository-level code editing tools that combine search, context, and editing into a unified workflow. These are building on the foundation of tree-sitter and embedding search.</p><h3 id="greptile" tabindex="-1">Greptile <a class="header-anchor" href="#greptile" aria-label="Permalink to &quot;Greptile&quot;">​</a></h3><p>An API for understanding codebases — provides semantic search and code intelligence as a service. Could enable agents to outsource code understanding.</p><h3 id="continue-dev" tabindex="-1">Continue.dev <a class="header-anchor" href="#continue-dev" aria-label="Permalink to &quot;Continue.dev&quot;">​</a></h3><p>An open-source AI coding assistant that integrates multiple context providers, demonstrating how to combine different code understanding tools into a unified system.</p><h3 id="bloop-now-acquired-by-sourcegraph" tabindex="-1">Bloop (now acquired by Sourcegraph) <a class="header-anchor" href="#bloop-now-acquired-by-sourcegraph" aria-label="Permalink to &quot;Bloop (now acquired by Sourcegraph)&quot;">​</a></h3><p>Was a code search engine using AI for natural language code search. Its approach of combining embedding search with code graph analysis influenced Cody&#39;s architecture.</p><hr><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ol><li><p><strong>Tree-sitter is the foundation.</strong> Every sophisticated code understanding system starts with tree-sitter. Its combination of speed, multi-language support, error tolerance, and incremental parsing makes it irreplaceable.</p></li><li><p><strong>ast-grep is the most underutilized tool.</strong> Its code-pattern-based search is perfect for agents that need structural code understanding, yet almost no agent uses it.</p></li><li><p><strong>SCIP/LSIF could bridge the LSP gap.</strong> Pre-computed code intelligence indexes would give CLI agents compiler-grade understanding without the startup cost of running language servers.</p></li><li><p><strong>Aider&#39;s repo map proves simple techniques work.</strong> Tree-sitter tags + PageRank ranking produces a codebase overview that dramatically improves LLM editing quality.</p></li><li><p><strong>The trend is toward composition.</strong> The best code understanding systems combine multiple tools — tree-sitter for parsing, ripgrep for search, embeddings for semantic matching, git for temporal context — rather than relying on any single tool.</p></li></ol>`,58))])}const D=i(y,[["render",g]]);export{C as __pageData,D as default};
